SELECT uuadm.*, ( SELECT cd_nm FROM AD_COMM_CD WHERE comm_grp_cd = 'ACC_UPD_MT_FG_CD' AND comm_cd = uuadm.upd_mt_fg_cd) upd_mt_fg_nm, ( SELECT cd_nm FROM AD_COMM_CD WHERE comm_grp_cd = 'ACC_DISTB_STS_CD' AND comm_cd = uuadm.acc_distb_sts_fg_cd) acc_distb_sts_fg_nm, ( SELECT user_nm FROM ad_user_mst WHERE user_id = uuadm.stm_fir_reg_user_id) stm_fir_reg_user_nm, ( SELECT user_nm FROM ad_user_mst WHERE user_id = uuadm.stm_last_upd_user_id) stm_last_upd_user_nm, usfd.sw_file_nm, usfd.sw_file_intro_msg FROM UM_UPD_ACC_DISTB_MST uuadm JOIN um_sw_file_dtl usfd ON usfd.sw_file_id = uuadm.sw_file_id WHERE 1 = 1
AND uuadm.acc_modl_id = #{accModlId}
AND uuadm.acc_sw_ver = #{accSwVer}
ORDER BY uuadm.stm_fir_reg_date DESC
